def _get_grid_subplot(fig, row, col, secondary_y=False):
    try:
        grid_ref = fig._grid_ref
    except AttributeError:
        raise Exception(
            "In order to reference traces by row and column, "
            "you must first use "
            "plotly.tools.make_subplots "
            "to create the figure with a subplot grid."
        )

    rows = len(grid_ref)
    cols = len(grid_ref[0])

    # Validate row
    if not isinstance(row, int) or row < 1 or rows < row:
        raise ValueError(
            """
The row argument to get_subplot must be an integer where 1 <= row <= {rows}
    Received value of type {typ}: {val}""".format(
                rows=rows, typ=type(row), val=repr(row)
            )
        )

    if not isinstance(col, int) or col < 1 or cols < col:
        raise ValueError(
            """
The col argument to get_subplot must be an integer where 1 <= row <= {cols}
    Received value of type {typ}: {val}""".format(
                cols=cols, typ=type(col), val=repr(col)
            )
        )

    subplot_refs = fig._grid_ref[row - 1][col - 1]
    if not subplot_refs:
        return None

    if secondary_y:
        if len(subplot_refs) > 1:
            layout_keys = subplot_refs[1].layout_keys
        else:
            return None
    else:
        layout_keys = subplot_refs[0].layout_keys

    if len(layout_keys) == 0:
        return SubplotDomain(**subplot_refs[0].trace_kwargs["domain"])
    elif len(layout_keys) == 1:
        return fig.layout[layout_keys[0]]
    elif len(layout_keys) == 2:
        return SubplotXY(
            xaxis=fig.layout[layout_keys[0]], yaxis=fig.layout[layout_keys[1]]
        )
    else:
        raise ValueError(
            """
Unexpected subplot type with layout_keys of {}""".format(
                layout_keys
            )
        )

def configure_oneshot_module(self, training_module: LightningModule) -> BaseOneShotLightningModule:
        if isinstance(self.temperature, float):
            temperature = LinearTemperatureScheduler(self.temperature, self.temperature)
        elif isinstance(self.temperature, tuple) and len(self.temperature) == 2:
            temperature = LinearTemperatureScheduler(*self.temperature)
        elif isinstance(self.temperature, dict) and 'init' in self.temperature and 'min' in self.temperature:
            temperature = LinearTemperatureScheduler(self.temperature['init'], self.temperature['min'])
        elif isinstance(self.temperature, LinearTemperatureScheduler):
            temperature = self.temperature
        else:
            raise ValueError(f'Invalid temperature: {self.temperature}')

        return GumbelDartsLightningModule(
            training_module=training_module,
            temperature_scheduler=temperature,
            arc_learning_rate=self.arc_learning_rate,
            gradient_clip_val=self.gradient_clip_val,
            log_prob_every_n_step=self.log_prob_every_n_step,
            warmup_epochs=self.warmup_epochs,
            penalty=self.penalty
        )

